sp_widget.client_script:
api.controller = function ($scope, $location) {
    const c = this;

    c.title = "SCM Demo Portal";

    c.navItems = [
        { label: "Incidents", pageId: "incidents", active: false },
        { label: "Contacts", pageId: "contacts", active: false },
        { label: "Tree demo", pageId: "contract_tree", active: false },
    ];

    updateActiveNavItem();

    $scope.$on("$locationChangeSuccess", function () {
        updateActiveNavItem();
    });

    function updateActiveNavItem() {
        const params = $location.search();
        const pageId = params.id || "";
        c.navItems.forEach((item) => {
            item.active = item.pageId === pageId;
        });
    }
};

sp_widget.css:
.nav-content {
    display: flex;
    flex-direction: row;
    align-items: center;
    height: inherit;
}

.nav-title {
    display: flex;
    flex-direction: row;
    align-items: center;
    font-weight: var(--scm-font-weight-bold);
    font-size: var(--scm-font-size-xxlarge);
    color: var(--scm-color-sc-navy);
    margin-right: var(--scm-spacing-7);
    height: inherit;
}

.nav-title:hover {
    cursor: pointer;
    font-weight: 701;
}

.nav-title a {
    color: inherit;
}

.nav-item {
    display: flex;
    flex-direction: row;
    align-items: center;
    font-size: var(--scm-font-size-medium);
    color: var(--scm-color-sc-navy);
    margin-right: var(--scm-spacing-5);
    height: inherit;
    cursor: pointer;
}

.nav-item-active {
    color: var(--scm-color-int-azure-active);
}

.nav-item a,
.nav-item a:visited,
.nav-item a:hover,
.nav-item a:focus,
.nav-item a:active {
    text-decoration: none !important;
    border: none !important;
    outline: none !important;
    box-shadow: none !important;
    color: inherit;
}

.nav-item:hover {
    font-weight: var(--scm-font-weight-semibold);
}

sp_widget.script:
(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    data.transactionId = transactionId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "scm-menu-instance.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });
})();
